package com.xda.sa2ration.lut;import java.util.ArrayList;import java.util.Collections;import java.util.Comparator;import java.util.List;public final class ColorCurve {public static final class Point {public final double x,y;public Point(double x,double y){if(!Double.isFinite(x)||!Double.isFinite(y)||x<0||x>1)throw new IllegalArgumentException("Ponto inválido");this.x=x;this.y=y;}}private final List<Point>points=new ArrayList<>();public ColorCurve(){points.add(new Point(0,0));points.add(new Point(1,1));}public void set(List<Point>input){if(input==null||input.size()<2)throw new IllegalArgumentException("Curva incompleta");points.clear();points.addAll(input);points.sort(Comparator.comparingDouble(p->p.x));}public List<Point>points(){return Collections.unmodifiableList(points);}}
